{
  "competency_groups": [
    {
      "code": "C1",
      "title": "Measurement and Stoichiometry",
      "description": "Competencies related to understanding matter, measurement uncertainties, laws of chemical combination, atomic theory, mole concept, and stoichiometric calculations.",
      "competencies": [
        "Understand the nature of matter and its properties including uncertainty in measurement",
        "Apply Laws of Chemical Combination and Dalton's Atomic Theory",
        "Calculate molecular masses using Mole Concept and perform Stoichiometric Calculations"
      ],
      "unit_name": "Some Basic Concepts of Chemistry",
      "chapter_name": "Some Basic Concepts of Chemistry"
    },
    {
      "code": "C2",
      "title": "Atomic Structure Models",
      "description": "Competencies related to the discovery of sub-atomic particles, evolution from Bohr's model to Quantum Mechanical Model.",
      "competencies": [
        "Trace the development of atomic models leading to the quantum mechanical model",
        "Explain Bohr's model for Hydrogen atom and its limitations"
      ],
      "unit_name": "Structure of Atom",
      "chapter_name": "Structure of Atom"
    },
    {
      "code": "C3",
      "title": "Periodic Classification and Trends",
      "description": "Competencies related to the classification of elements, periodic law, electronic configuration blocks, and trends in properties.",
      "competencies": [
        "Apply Modern Periodic Law and understand the structure of the Periodic Table",
        "Determine electronic configurations for s-, p-, d-, f- block elements"
      ],
      "unit_name": "Classification of Elements and Periodicity in Properties",
      "chapter_name": "Classification of Elements and Periodicity in Properties"
    },
    {
      "code": "C4",
      "title": "Chemical Bonding Theories",
      "description": "Competencies related to various theories of chemical bonding, hybridization, molecular geometry, and intermolecular forces.",
      "competencies": [
        "Apply Kossel-Lewis approach and VSEPR theory for predicting molecular shapes"
      ],
      "unit_name": "Chemical Bonding and Molecular Structure",
      "chapter_name": "Chemical Bonding and Molecular Structure"
    },
    {
      "code": "C5",
      "title": "Thermodynamic Principles",
      "description": "Competencies related to thermodynamic terms, enthalpy changes, spontaneity, Gibbs energy, and calorimetry.",
      "competencies": [
        "Calculate Enthalpy Change (Delta H) using Calorimetry"
      ],
      "unit_name": "Thermodynamics",
      "chapter_name": "Thermodynamics"
    },
    {
      "code": "C6",
      "title": "Chemical and Ionic Equilibrium",
      "description": "Competencies related to dynamic equilibrium, equilibrium constants (K), reaction quotient (Q), Gibbs energy relationship, and ionic equilibria.",
      "competencies": [
        "Analyze the relationship between K, Q, and Gibbs Energy"
      ],
      "unit_name": "Equilibrium",
      "chapter_name": "Equilibrium"
    },
    {
      "code": "C7",
      "title": "Redox Reactions",
      "description": "Competencies related to oxidation-reduction concepts, electron transfer, and balancing redox reactions.",
      "competencies": [
        "Determine Oxidation Numbers and balance Redox Reactions"
      ],
      "unit_name": "Redox Reactions",
      "chapter_name": "Redox Reactions"
    },
    {
      "code": "C8",
      "title": "Organic Chemistry Fundamentals",
      "description": "Competencies related to tetravalence of carbon, nomenclature, isomerism, reaction mechanisms, and purification techniques.",
      "competencies": [
        "Apply IUPAC nomenclature rules for organic compounds"
      ],
      "unit_name": "Organic Chemistry: Some basic Principles and Techniques",
      "chapter_name": "Organic Chemistry: Some basic Principles and Techniques"
    },
    {
      "code": "C9",
      "title": "Hydrocarbon Classification and Reactivity",
      "description": "Competencies related to the classification, properties, and reactions of alkanes, alkenes, alkynes, and aromatic hydrocarbons.",
      "competencies": [
        "Differentiate between saturated and unsaturated hydrocarbons"
      ],
      "unit_name": "Hydrocarbons",
      "chapter_name": "Hydrocarbons"
    },
    {
      "code": "C10",
      "title": "Solution Chemistry and Colligative Properties",
      "description": "Competencies related to types of solutions, concentration expressions, vapor pressure, ideal/non-ideal behavior, and colligative properties.",
      "competencies": [
        "Determine molar mass using Colligative Properties"
      ],
      "unit_name": "Unit 1: Solutions",
      "chapter_name": "Unit 1: Solutions"
    },
    {
      "code": "C11",
      "title": "Electrochemistry and Cells",
      "description": "Competencies related to galvanic/electrolytic cells, Nernst equation, conductance, batteries, fuel cells, and corrosion.",
      "competencies": [
        "Apply the Nernst Equation for cell potential calculations"
      ],
      "unit_name": "Unit 2: Electrochemistry",
      "chapter_name": "Unit 2: Electrochemistry"
    },
    {
      "code": "C12",
      "title": "Chemical Kinetics and Reaction Rates",
      "description": "Competencies related to reaction rates, factors influencing rate, integrated rate equations, temperature dependence, and collision theory.",
      "competencies": [
        "Interpret Integrated Rate Equations for different orders of reactions"
      ],
      "unit_name": "Unit 3: Chemical Kinetics",
      "chapter_name": "Unit 3: Chemical Kinetics"
    },
    {
      "code": "C13",
      "title": "d and f Block Elements Properties",
      "description": "Competencies related to the position, electronic configuration, general properties of transition elements, lanthanoids, actinoids, and their applications.",
      "competencies": [
        "Describe General properties of Transition Elements (d-Block)"
      ],
      "unit_name": "Unit 4: d and f Block Elements",
      "chapter_name": "Unit 4: d and f Block Elements"
    },
    {
      "code": "C14",
      "title": "Coordination Compounds Theory",
      "description": "Competencies related to Werner's theory, nomenclature, isomerism, bonding theories (Valence Bond/Molecular Orbital), and applications.",
      "competencies": [
        "Apply IUPAC Nomenclature rules for Coordination Compounds"
      ],
      "unit_name": "Unit 5: Coordination Compounds",
      "chapter_name": "Unit 5: Coordination Compounds"
    },
    {
      "code": "C15",
      "title": "Organic Functional Groups and Synthesis",
      "description": "Competencies related to Haloalkanes, Alcohols, Phenols, Ethers, Carbonyl compounds (Aldehydes/Ketones/Acids), Amines, and Diazonium salts.",
      "competencies": [
        "Identify methods of preparation for various organic functional groups"
      ],
      "unit_name": "Unit 6: Haloalkanes and Haloarenes",
      "chapter_name": "Haloalkanes and Haloarenes"
    },
    {
      "code": "C16",
      "title": "Biomolecules Structure and Function",
      "description": "Competencies related to the structure, classification, and biological functions of carbohydrates, proteins, enzymes, vitamins, nucleic acids, and hormones.",
      "competencies": [
        "Classify Biomolecules based on their structural units"
      ],
      "unit_name": "Unit 10: Biomolecules",
      "chapter_name": "Biomolecules"
    }
  ]
}
